        'status': 'healthy',
        'service': 'devops-demo',
        'version': '1.0.0'
    })

@app.route('/')
def index():
    return jsonify({
        'message': 'Hello from DevOps Demo!',
        'endpoints': ['/health', '/api/info']
    })

@app.route('/api/info')
def info():
    return jsonify({
        'python_version': sys.version,
        'environment': os.environ.get('ENV', 'development')
    })

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)
